40	 * If the maximum out-of-sequence time difference between elements within a stream is known, the <code>timeout</code>
41	 * value should be set to this value. In this case it is guaranteed that all elements of a stream will be delivered in
42	 * sequence via the {@link SequenceSender}. The lower the <code>timeout</code> value is compared to the out-of-sequence
43	 * time difference between elements within a stream the higher the probability is for out-of-sequence elements delivered
44	 * by this resequencer. Delivery of elements must be explicitly triggered by applications using the {@link #deliver()}
45	 * or {@link #deliverNext()} methods. Only elements that are <i>ready-for-delivery</i> are delivered by these methods.
46	 * The longer an application waits to trigger a delivery the more elements may become <i>ready-for-delivery</i>.
47	 * <p>
48	 * The resequencer remembers the last-delivered element. If an element arrives which is the immediate successor of the
49	 * last-delivered element it is <i>ready-for-delivery</i> immediately. After delivery the last-delivered element is
50	 * adjusted accordingly. If the last-delivered element is <code>null</code> i.e. the resequencer was newly created the
51	 * first arriving element needs <code>timeout</code> milliseconds in any case for becoming <i>ready-for-delivery</i>.
52	 * <p>
53	 */
54	public class ResequencerEngine<E> {
55	
56	    /**
57	     * The element that most recently hash been delivered or <code>null</code> if no element has been delivered yet.
58	     */
59	    private Element<E> lastDelivered;
60	
61	    /**
62	     * Minimum amount of time to wait for out-of-sequence elements.
63	     */
64	    private long timeout;
65	
66	    /**
67	     * A sequence of elements for sorting purposes.
68	     */
69	    private final Sequence<Element<E>> sequence;
70	
71	    /**
72	     * A timer for scheduling timeout notifications.
73	     */
74	    private Timer timer;
75	
76	    /**
77	     * A strategy for sending sequence elements.
78	     */
79	    private SequenceSender<E> sequenceSender;
80	
81	    /**
82	     * Indicates whether an error should be thrown if message older (based on Comparator) than the last delivered
83	     * message is received.
84	     */
85	    private Boolean rejectOld;
86	
87	    /**
88	     * List containing wait conditions to be evaluated whenever the sequence is modified. Access to this field should be
89	     * done inside a lock block.
90	     */
91	    private final Map<CountDownLatch, Predicate<Sequence<?>>> waitConditions = new HashMap<>();
92	
93	    private final Lock lock = new ReentrantLock();
94	
95	    /**
96	     * Creates a new resequencer instance with a default timeout of 2000 milliseconds.
97	     *
98	     * @param comparator a sequence element comparator.
99	     */
100	    public ResequencerEngine(SequenceElementComparator<E> comparator) {
101	        this.sequence = createSequence(comparator);
102	        this.timeout = 2000L;
103	        this.lastDelivered = null;
104	    }
105	
106	    public void start() {
107	        timer = new Timer(
108	                ThreadHelper.resolveThreadName("Camel Thread ${counter} - ${name}", "Stream Resequencer Timer"), true);
109	    }
110	
111	    /**
112	     * Stops this resequencer (i.e. this resequencer's {@link Timer} instance).
113	     */
114	    public void stop() {
115	        timer.cancel();
116	    }
117	
118	    /**
119	     * Returns the number of elements currently maintained by this resequencer.
120	     *
121	     * @return the number of elements currently maintained by this resequencer.
122	     */
123	    public int size() {
124	        lock.lock();
125	        try {
126	            return sequence.size();
127	        } finally {
128	            lock.unlock();
129	        }
130	    }
131	
132	    /**
133	     * Wait for the following condition to happen. Do not call this method while holding a lock on the resequencer
134	     * engine, as it will deadlock. The predicate will be evaluated while holding a lock on the resequencer engine.
135	     *
136	     * @param  pred                 the condition to wait for
137	     * @throws InterruptedException if the thread is interrupted
138	     */
139	    public void waitUntil(Predicate<Sequence<?>> pred) throws InterruptedException {
140	        CountDownLatch latch;
141	        lock.lock();
142	        try {
143	            if (pred.test(sequence)) {
144	                return;
145	            }
146	            latch = new CountDownLatch(1);
147	            waitConditions.put(latch, pred);
148	        } finally {
149	            lock.unlock();
150	        }
151	        latch.await();
152	    }
153	
154	    private void evaluateConditions() {
155	        lock.lock();
156	        try {
157	            for (var it = waitConditions.entrySet().iterator(); it.hasNext();) {
158	                Map.Entry<CountDownLatch, Predicate<Sequence<?>>> e = it.next();
159	                if (e.getValue().test(sequence)) {
160	                    e.getKey().countDown();
161	                    it.remove();
162	                }
163	            }
164	        } finally {
165	            lock.unlock();
166	        }
167	    }
168	
169	    /**
170	     * Returns this resequencer's timeout value.
171	     *
172	     * @return the timeout in milliseconds.
173	     */
174	    public long getTimeout() {
175	        return timeout;
176	    }
177	
178	    /**
179	     * Sets this sequencer's timeout value.
180	     *
181	     * @param timeout the timeout in milliseconds.
182	     */
183	    public void setTimeout(long timeout) {
184	        this.timeout = timeout;
185	    }
186	
187	    public Boolean getRejectOld() {
188	        return rejectOld;
189	    }
190	
191	    public void setRejectOld(Boolean rejectOld) {
192	        this.rejectOld = rejectOld;
193	    }
194	
195	    /**
196	     * Returns the sequence sender.
197	     *
198	     * @return the sequence sender.
199	     */
200	    public SequenceSender<E> getSequenceSender() {
201	        return sequenceSender;
202	    }
