41	    /**
42	     * Returns the immediate predecessor of the given element in this sequence or <code>null</code> if no predecessor
43	     * exists.
44	     *
45	     * @param  e an element which is compared to elements of this sequence.
46	     * @return   an element of this sequence or <code>null</code>.
47	     */
48	    public E predecessor(E e) {
49	        E elem = lower(e);
50	        if (elem == null) {
51	            return null;
52	        }
53	        if (seqComparator().predecessor(elem, e)) {
54	            return elem;
55	        }
56	        return null;
57	    }
