288	            final Comparator<? super Exchange> comparator, boolean allowDuplicates, boolean reverse) {
289	        Comparator<? super Exchange> answer = comparator;
290	
291	        if (reverse) {
292	            answer = comparator.reversed();
293	        }
294	
295	        // if we allow duplicates then we need to cater for that in the comparator
296	        if (allowDuplicates) {
297	            // they are equal but we should allow duplicates so say that o2 is higher
298	            // so it will come next
299	            answer = answer.thenComparing((o1, o2) -> 1);
