313	    /**
314	     * A strategy method to decide if the "out" batch is completed. That is, whether the resulting exchange in the out
315	     * collection should be sent.
316	     */
317	    private boolean isOutBatchCompleted() {
318	        if (outBatchSize == 0) {
319	            // out batch is disabled, so go ahead and send.
320	            return true;
321	        }
322	        return !collection.isEmpty() && collection.size() >= outBatchSize;
323	    }
324	
325	    /**
326	     * Strategy Method to process an exchange in the batch. This method allows derived classes to perform custom
327	     * processing before or after an individual exchange is processed
328	     */
329	    protected void processExchange(Exchange exchange) {
330	        processor.process(exchange, sync -> postProcess(exchange));
331	    }
332	
333	    protected void postProcess(Exchange exchange) {
334	        if (exchange.getException() != null) {
335	            getExceptionHandler().handleException("Error processing aggregated exchange: " + exchange, exchange,
336	                    exchange.getException());
337	        }
338	    }
339	
340	    @Override
341	    protected void doBuild() throws Exception {
342	        ServiceHelper.buildService(processor);
343	    }
344	
345	    @Override
346	    protected void doInit() throws Exception {
347	        ServiceHelper.initService(processor);
348	    }
349	
350	    @Override
351	    protected void doStart() throws Exception {
352	        ServiceHelper.startService(processor);
353	        sender = new BatchSender();
354	        sender.start();
355	    }
356	
357	    @Override
358	    protected void doStop() throws Exception {
359	        if (sender != null) {
360	            try {
361	                sender.cancel();
362	            } catch (Exception e) {
363	                // ignore
364	            }
365	            sender = null;
366	        }
367	        ServiceHelper.stopService(processor);
368	    }
369	
370	    /**
371	     * Enqueues an exchange for later batch processing.
372	     */
373	    @Override
374	    public boolean process(Exchange exchange, AsyncCallback callback) {
375	        try {
376	            // if batch consumer is enabled then we need to adjust the batch size
377	            // with the size from the batch consumer
378	            if (isBatchConsumer()) {
379	                int size = exchange.getProperty(ExchangePropertyKey.BATCH_SIZE, Integer.class);
380	                if (batchSize != size) {
381	                    batchSize = size;
382	                    LOG.trace("Using batch consumer completion, so setting batch size to: {}", batchSize);
383	                }
384	            }
385	
386	            // validate that the exchange can be used
387	            if (!isValid(exchange)) {
388	                if (isIgnoreInvalidExchanges()) {
389	                    LOG.debug("Invalid Exchange. This Exchange will be ignored: {}", exchange);
390	                } else {
391	                    throw new CamelExchangeException("Exchange is not valid to be used by the BatchProcessor", exchange);
392	                }
393	            } else {
394	                // exchange is valid so enqueue the exchange
395	                sender.enqueueExchange(exchange);
396	            }
397	        } catch (Exception e) {
398	            exchange.setException(e);
399	        }
400	        callback.done(true);
401	        return true;
402	    }
403	
404	    /**
405	     * Is the given exchange valid to be used.
406	     *
407	     * @param  exchange the given exchange
408	     * @return          <tt>true</tt> if valid, <tt>false</tt> otherwise
409	     */
410	    private boolean isValid(Exchange exchange) {
411	        Object result = null;
412	        try {
413	            result = expression.evaluate(exchange, Object.class);
414	        } catch (Exception e) {
415	            LOG.debug("Error evaluating expression: {}. This exception is ignored.", expression, e);
416	        }
417	        return result != null;
418	    }
419	
420	    /**
421	     * Sender thread for queued-up exchanges.
422	     */
423	    private class BatchSender extends Thread {
424	
425	        private final Queue<Exchange> queue;
426	        private final Lock queueLock = new ReentrantLock();
427	        private final AtomicBoolean exchangeEnqueued = new AtomicBoolean();
428	        private final Queue<String> completionPredicateMatched = new ConcurrentLinkedQueue<>();
429	        private final Condition exchangeEnqueuedCondition = queueLock.newCondition();
430	
431	        BatchSender() {
432	            super(camelContext.getExecutorServiceManager().resolveThreadName("Batch Sender"));
433	            this.queue = new LinkedList<>();
434	        }
435	
436	        @Override
437	        public void run() {
438	            // Wait until one of either:
439	            // * an exchange being queued;
440	            // * the batch timeout expiring; or
441	            // * the thread being cancelled.
442	            //
443	            // If an exchange is queued then we need to determine whether the
444	            // batch is complete. If it is complete then we send out the batched
445	            // exchanges. Otherwise we move back into our wait state.
446	            //
447	            // If the batch times out then we send out the batched exchanges
448	            // collected so far.
449	            //
450	            // If we receive an interrupt then all blocking operations are
451	            // interrupted and our thread terminates.
452	            //
453	            // The goal of the following algorithm in terms of synchronisation
454	            // is to provide fine grained locking i.e. retaining the lock only
455	            // when required. Special consideration is given to releasing the
456	            // lock when calling an overloaded method i.e. sendExchanges.
457	            // Unlocking is important as the process of sending out the exchanges
458	            // would otherwise block new exchanges from being queued.
459	
460	            queueLock.lock();
461	            try {
462	                do {
463	                    try {
464	                        if (!exchangeEnqueued.get()) {
465	                            LOG.trace("Waiting for new exchange to arrive or batchTimeout to occur after {} ms.", batchTimeout);
466	                            exchangeEnqueuedCondition.await(batchTimeout, TimeUnit.MILLISECONDS);
467	                        }
468	
469	                        // if the completion predicate was triggered then there is an exchange id which denotes when to complete
470	                        String id = null;
471	                        if (!completionPredicateMatched.isEmpty()) {
472	                            id = completionPredicateMatched.poll();
473	                        }
474	
475	                        if (id != null || !exchangeEnqueued.get()) {
476	                            if (id != null) {
477	                                LOG.trace("Collecting exchanges to be aggregated triggered by completion predicate");
478	                            } else {
479	                                LOG.trace("Collecting exchanges to be aggregated triggered by batch timeout");
480	                            }
481	                            drainQueueTo(collection, batchSize, id);
482	                        } else {
483	                            exchangeEnqueued.set(false);
484	                            boolean drained = false;
485	                            while (isInBatchCompleted(queue.size())) {
486	                                drained = true;
487	                                drainQueueTo(collection, batchSize, id);
488	                            }
489	                            if (drained) {
490	                                LOG.trace("Collecting exchanges to be aggregated triggered by new exchanges received");
491	                            }
492	
493	                            if (!isOutBatchCompleted()) {
494	                                continue;
495	                            }
496	                        }
497	
498	                        queueLock.unlock();
499	                        try {
500	                            try {
501	                                sendExchanges();
502	                            } catch (Exception t) {
503	                                // a fail safe to handle all exceptions being thrown
504	                                getExceptionHandler().handleException(t);
505	                            }
506	                        } finally {
507	                            queueLock.lock();
508	                        }
509	
510	                    } catch (InterruptedException e) {
511	                        Thread.currentThread().interrupt();
512	                        break;
513	                    }
514	
515	                } while (isRunAllowed());
516	
517	            } finally {
518	                queueLock.unlock();
519	            }
520	        }
521	
522	        /**
523	         * This method should be called with queueLock held
524	         */
525	        private void drainQueueTo(Collection<Exchange> collection, int batchSize, String exchangeId) {
526	            for (int i = 0; i < batchSize; ++i) {
527	                Exchange e = queue.poll();
528	                if (e != null) {
529	                    try {
530	                        collection.add(e);
531	                    } catch (Exception t) {
532	                        e.setException(t);
533	                    } catch (Throwable t) {
534	                        getExceptionHandler().handleException("Error adding exchange", e, t);
535	                    }
536	                    if (exchangeId != null && exchangeId.equals(e.getExchangeId())) {
537	                        // this batch is complete so stop draining
538	                        break;
539	                    }
540	                } else {
541	                    break;
542	                }
543	            }
544	        }
545	
546	        public void cancel() {
547	            interrupt();
548	        }
549	
550	        public void enqueueExchange(Exchange exchange) {
551	            LOG.debug("Received exchange to be batched: {}", exchange);
552	            queueLock.lock();
553	            try {
554	                // pre test whether the completion predicate matched
555	                if (completionPredicate != null) {
556	                    boolean matches = completionPredicate.matches(exchange);
557	                    if (matches) {
558	                        LOG.trace("Exchange matched completion predicate: {}", exchange);
559	                        // add this exchange to the list of exchanges which marks the batch as complete
560	                        completionPredicateMatched.add(exchange.getExchangeId());
561	                    }
562	                }
563	                // need to make defensive copy that are put on the sequencer queue
564	                Exchange copy = ExchangeHelper.createCorrelatedCopy(exchange, true);
565	                queue.add(copy);
566	                exchangeEnqueued.set(true);
567	                exchangeEnqueuedCondition.signal();
568	            } finally {
569	                queueLock.unlock();
570	            }
571	        }
572	
573	        private void sendExchanges() {
574	            Iterator<Exchange> iter = collection.iterator();
575	            while (iter.hasNext()) {
576	                Exchange exchange = iter.next();
577	                iter.remove();
578	                LOG.debug("Sending aggregated exchange: {}", exchange);
579	                processExchange(exchange);
580	            }
581	        }
582	    }
583	
584	}
