package org.apache.camel.processor.resequencer;

/**
 * A {@link SequenceElementComparator} that reverses the ordering of another {@link SequenceElementComparator}, so
 * that elements are released in descending rather than ascending order.
 * <p/>
 * Reversing {@link #compare(Object, Object)} alone is not sufficient: the {@link ResequencerEngine} also relies on
 * {@link #predecessor(Object, Object)} and {@link #successor(Object, Object)} to decide when a waiting element can be
 * released without waiting out its timeout. Since the release order is reversed, the meaning of "predecessor" and
 * "successor" swap as well, so this decorator swaps the two delegate calls in addition to reversing the comparison.
 */
class ReverseSequenceElementComparator<E> implements SequenceElementComparator<E> {

    /**
     * A sequence element comparator this comparator delegates to.
     */
    private final SequenceElementComparator<E> comparator;

    /**
     * Creates a new reverse element comparator instance.
     *
     * @param comparator a sequence element comparator this comparator delegates to.
     */
    ReverseSequenceElementComparator(SequenceElementComparator<E> comparator) {
        this.comparator = comparator;
    }

    @Override
    public boolean predecessor(E o1, E o2) {
        return comparator.successor(o1, o2);
    }

    @Override
    public boolean successor(E o1, E o2) {
        return comparator.predecessor(o1, o2);
    }

    @Override
    public int compare(E o1, E o2) {
        return comparator.compare(o2, o1);
    }

    @Override
    public boolean isValid(E o1) {
        return comparator.isValid(o1);
    }

    @Override
    public String toString() {
        return comparator.toString();
    }
}

